import{_ as e,o as a,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Packaging","description":"","frontmatter":{"title":"Packaging","slug":"packaging-archived"},"headers":[],"relativePath":"marketer-hub/packaging-archived.md","filePath":"marketer-hub/packaging-archived.md"}'),o={name:"marketer-hub/packaging-archived.md"};function i(d,t,s,h,c,l){return a(),r("div",null,[...t[0]||(t[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <strong>Branch Growth Platform</strong> is the foundational layer on which all the powerful capabilities associated with your Branch account are built.</p><p>The Branch Growth Platform is home to our three main product offerings: <strong>Engagement</strong>, <strong>Performance</strong>, and <strong>Activation</strong>.</p><p>We have several <strong>add-ons</strong> you can choose from. Each add-on includes a set of features that offer advanced solutions to complex problems.</p><p>To round it out, we also offer <strong>customer support services</strong>, so you can feel confident through every part of Branch implementation; from integration all the way up through expansion and maintenance.</p><p>This guide is a closer look at the features associated with each package, and includes links to helpful documentation where you can learn more about each one.</p><h2 id="branch-growth-platform" tabindex="-1">Branch Growth Platform <a class="header-anchor" href="#branch-growth-platform" aria-label="Permalink to &quot;Branch Growth Platform&quot;">​</a></h2><p>Below are all the features included in the Branch Growth Platform for all users of Branch.</p><p>Customers who are not on a contracted plan will still need to enter a valid credit card into the Branch Dashboard within 30 days of creating an account, and will be responsible for volume credit usages on their Branch account.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="./submit-a-ticket.html">Standard Support</a></td><td>Access to our global technical support team.</td></tr><tr><td><a href="./branch-dashboard-overview.html">Admin Tools</a></td><td><strong>Basic</strong> admin tools in the Branch Dashboard.</td></tr><tr><td><a href="https://university.branch.io/paths" target="_blank" rel="noreferrer">Branch University</a></td><td>Our customer education platform for Branch coursework. Includes the certification program.</td></tr><tr><td><a href="./linkhub.html#analytics">Link Management</a></td><td>Link management and configuration, including templates and bulk tools.</td></tr><tr><td><a href="./tealium-import.html">CDP Data Imports</a></td><td>Import data into Branch from a customer data platform. Current providers include Tealium, Segment, and mParticle.</td></tr><tr><td><a href="./deepviews.html">Deepviews</a></td><td>Mobile web splash pages, hosted by Branch, that give a preview of the in-app content behind a given Branch Link.</td></tr><tr><td><a href="./creating-a-deep-link.html">Deep Links</a></td><td>Route users directly to the content you want them to see, based on whether or not they have your app installed.</td></tr><tr><td><a href="./san-deferred-deep-linking.html">Deferred Deep Links</a></td><td>Configure deep linking to execute through an install. Includes <a href="./nativelink-deferred-deep-linking.html">NativeLink</a>.</td></tr><tr><td><a href="./app-api.html">App API</a></td><td>View and make updates to an existing Branch app configuration.</td></tr><tr><td><a href="./data-subject-request-branch-api.html">Data Subject Request API</a></td><td>Access and erase end-user personal data from Branch.</td></tr></tbody></table><h2 id="engagement-product" tabindex="-1">Engagement product <a class="header-anchor" href="#engagement-product" aria-label="Permalink to &quot;Engagement product&quot;">​</a></h2><p>The Engagement product is for marketers focused on linking and attribution for both owned and organic marketing channels.</p><p>With Engagement, you can drive customer loyalty, increase app adoption and retention, and manage channels such as offline, web, email, and social. You can also measure the impact of these channels to improve user lifetime value.</p><h3 id="engagement-essentials-tier" tabindex="-1">Engagement Essentials tier <a class="header-anchor" href="#engagement-essentials-tier" aria-label="Permalink to &quot;Engagement Essentials tier&quot;">​</a></h3><p>Drive growth from owned and organic channels with linking experiences that convert.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="./deep-linking-api.html">Deep Linking API</a></td><td>Generate Branch Deep Links at scale, and give them analytics tags.</td></tr><tr><td><a href="./create-quick-links.html">Short Links</a></td><td>Create Branch Links with custom redirects, analytics information, and social media tags. This includes Branch Ad Links and Referral Links.</td></tr><tr><td><a href="./linkhub.html#analytics">Link-Level Analytics</a></td><td>View your campaign performance through customizable tables with download capabilities.</td></tr><tr><td><a href="./create-qr-codes.html">Dynamic QR Codes</a></td><td>Create Branch QR Codes and set your own parameters so your user has a seamless experience to your app. No visual customization.</td></tr><tr><td><a href="./analyze-qr-code-performance.html">QR Code Analytics</a></td><td>Generate and view reports for your Branch QR Code campaigns.</td></tr><tr><td><a href="./universal-email-integration-guide.html">ESP Integrations</a></td><td>Automatically convert your email links into multi-platform Branch Deep Links that take users directly to content in your mobile app. Maintain the same web experience for desktop and mobile users without the app.</td></tr><tr><td><a href="https://branch.dashboard.branch.io/email/activity" target="_blank" rel="noreferrer">Email Analytics</a></td><td>Analyze your email campaign performance directly in the Branch Dashboard.</td></tr><tr><td><a href="./journeys-overview.html">Journeys</a></td><td>Smart banners to help you convert web users to app users. Includes mobile web banners and desktop web banners. This includes <a href="./journeys-assist.html">Journeys Assist</a>.</td></tr><tr><td><a href="./seo-app-attribution.html">SEO App Attribution</a></td><td>Attribute downstream app events from organic search traffic.</td></tr><tr><td><a href="./dashboard-daily-exports.html">Daily Exports</a> + <a href="./daily-exports-api.html">Daily Exports API</a></td><td>Export all device-level data in batches on a daily basis. Accessed through the Branch Dashboard or via API.</td></tr><tr><td><a href="./dashboard-custom-exports.html">Custom Exports</a> + <a href="./custom-exports-api.html">Custom Exports API</a></td><td>Export select device-level data using your own filters. Accessed through the Branch Dashboard or via API.</td></tr><tr><td><a href="./query-api.html">Query API</a></td><td>Use your own unique queries to fetch pre-aggregated analytics data.</td></tr><tr><td><a href="./aggregate-api.html">Aggregate API</a></td><td>Query and export aggregate analytics.</td></tr><tr><td><a href="./cohort-analytics.html">Cohort Analytics</a> + <a href="./cohort-api.html">Cohort API</a></td><td>Analyze your cross-channel, cross-platform Branch data by either acquisition or re-engagement date to see how those users performed over time. Accessed through the Branch Dashboard or via API.</td></tr><tr><td><a href="./events-api.html">Events API</a></td><td>Track events (end-user actions) that take place in your app.</td></tr><tr><td><a href="./attribution-api.html">Attribution API</a></td><td>Track Install, Reinstall, and Open events alongside a payload of attribution properties.</td></tr><tr><td><a href="./basic-link-configuration.html#use-your-own-domain">Custom Branded Domain</a></td><td>Configure your Branch Links to use your own custom domain.</td></tr><tr><td><a href="./add-and-manager-users.html">Additional Users</a></td><td>Add up to 5 additional users to your Branch account.</td></tr></tbody></table><h3 id="engagement-pro-tier" tabindex="-1">Engagement Pro tier <a class="header-anchor" href="#engagement-pro-tier" aria-label="Permalink to &quot;Engagement Pro tier&quot;">​</a></h3><p>Maximize conversions from every owned and organic channel with more creative control, A/B testing for optimization, and APIs for scale.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="./quick-links-api.html">Short Links API</a></td><td>Generate Branch at scale, and see them appear in the Branch Dashboard later.</td></tr><tr><td><a href="./qr-codes-builder.html">Custom QR Codes</a></td><td>Customize Branch QR Code logos, imagery, shapes, and colors to increase conversions right from the Branch Dashboard.</td></tr><tr><td><a href="./qr-code-api.html">QR Code API</a></td><td>Generate Branch QR Codes at scale, each with a unique Branch Link.</td></tr><tr><td><a href="./deepviews.html">Deepview HTML Editor</a></td><td>Customize individual Deepviews to meet the needs of your brand and campaign using our HTML Editor.</td></tr><tr><td><a href="./journeys-overview.html">Journeys</a> (Advanced)</td><td>Advanced Journeys capabilities, including A/B testing, additional customization options and creative types, and more sophisticated targeting.</td></tr></tbody></table><h2 id="performance-product" tabindex="-1">Performance product <a class="header-anchor" href="#performance-product" aria-label="Permalink to &quot;Performance product&quot;">​</a></h2><p>Use the Performance product to improve your ads ROI with accurate attribution and insights.</p><p>The Performance product helps you justify your ad spend effectiveness by showing ROI, while still helping you manage evolving privacy regulations and gaps in performance data. Make your marketing budget go further by future-proofing your marketing with advanced, privacy-preserving attribution that maintains comprehensive measurement.</p><h3 id="performance-essentials-tier" tabindex="-1">Performance Essentials tier <a class="header-anchor" href="#performance-essentials-tier" aria-label="Permalink to &quot;Performance Essentials tier&quot;">​</a></h3><p>Improve your ads ROI with accurate attribution.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="./ad-links.html">Ad Links</a></td><td>Power your ads with Branch Ad Links and accurately attribute resulting app conversions to the appropriate advertising partner.</td></tr><tr><td><a href="./universal-ad-partner-integration-guide.html">Ad Partner Integrations</a> (Postbacks)</td><td>Connect an <strong>unlimited</strong> numberof ad partners from our list to your Branch account so you can track campaign performance.</td></tr><tr><td><a href="./adding-custom-partners.html">Custom Ad Partner Integrations</a></td><td>Connect <strong>up to 3</strong> new ad partners that do not have official Branch integrations.</td></tr><tr><td><a href="./unified-analytics.html">Unified Analytics</a></td><td>See campaign data from all attribution methods (SKAN, IDFA, IDFV, Apple Ads, and Android) in a single view after removing duplicate SKAN data.</td></tr><tr><td><a href="./retrieving-branchs-last-attributed-touch-data.html">Last-Touch Attribution</a></td><td>Attribute app conversions to the most recent click or impression.</td></tr><tr><td><a href="./data-integration-partners.html">Data Partner Integrations</a> (webhooks)</td><td>Connect an <strong>unlimited</strong> number of data integration partners to export install and down-funnel user action data to your internal systems for real-time analysis as it happens.</td></tr><tr><td><a href="./skadnetwork.html">Privacy-Preserving Attribution</a></td><td>Expand attribution coverage across iOS with Predictive Aggregated Measurement alongside SKAN.</td></tr><tr><td><a href="./fraud.html">Fraud Defense</a></td><td>Help protect your ad budget from fraud and eliminate low-quality traffic with our machine learning-driven blocking rules, dashboard visibility, and hands-on fraud mitigation support.</td></tr><tr><td><a href="./seo-app-attribution.html">SEO App Attribution</a></td><td>Attribute downstream app events from organic search traffic.</td></tr><tr><td><a href="./events-api.html">Events API</a></td><td>Track events (end-user actions) that take place in your app.</td></tr><tr><td><a href="./attribution-api.html">Attribution API</a></td><td>Track Install, Reinstall, and Open events alongside a payload of attribution properties.</td></tr><tr><td><a href="./basic-link-configuration.html#use-your-own-domain">Custom Branded Domain</a></td><td>Configure your Branch Links to use your own custom domain.</td></tr><tr><td><a href="./add-and-manager-users.html">Additional Users</a></td><td>Add up to 5 additional users to your Branch account.</td></tr></tbody></table><h3 id="performance-pro-tier" tabindex="-1">Performance Pro tier <a class="header-anchor" href="#performance-pro-tier" aria-label="Permalink to &quot;Performance Pro tier&quot;">​</a></h3><p>Maximize your ads ROI with sophisticated cost analysis, audience building, and mobile and household attribution.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="./multi-touch-attribution.html">Multi-Touch Attribution</a></td><td>Identify all the SANs a user interacted with on their journey to convert, including those that did not receive credit.</td></tr><tr><td><a href="./adding-custom-partners.html">Custom Ad Partner Integrations</a></td><td>Connect an <strong>unlimited</strong> number of new ad partners that do not have official Branch integrations.</td></tr><tr><td><a href="./roi-hub.html">ROI Hub</a></td><td>Unlock deeper insights into your marketing performance and see the impact of your ad spend with access to centralized cost data. Seamlessly track the true return on investment (ROI) of your campaigns with automated cost data ingestion. Easily monitor your ad partner cost connections with real-time monitoring, allowing you to quickly identify and resolve issues.</td></tr><tr><td><a href="./household-measurement.html">Household Measurement</a></td><td>Analyze and report on conversions across mobile, web, and living room devices.</td></tr><tr><td><a href="./engagement-builder.html">Engagement Builder</a></td><td>Build groups to re-engage users, boost purchase likelihood, and increase session frequency.</td></tr></tbody></table><h2 id="activation-product" tabindex="-1">Activation product <a class="header-anchor" href="#activation-product" aria-label="Permalink to &quot;Activation product&quot;">​</a></h2><p>The Activation product is for organizations needing to create, manage, and analyze shortened links and QR codes at scale.</p><p>With Activation, you can increase click-through rates with branded links, unify your linking strategy in one secure platform, and empower marketing teams while maintaining enterprise-grade governance and control.</p><h3 id="activation-essentials-tier" tabindex="-1">Activation Essentials tier <a class="header-anchor" href="#activation-essentials-tier" aria-label="Permalink to &quot;Activation Essentials tier&quot;">​</a></h3><p>Create branded Short Links and custom QR codes that work everywhere.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="./creating-a-deep-link.html">App Links</a></td><td>Route users directly to the content you want them to see, based on whether or not they have your app installed.</td></tr><tr><td><a href="./create-quick-links.html">Web Links</a></td><td>Route users to a webpage with a branded web-only Short Link.</td></tr><tr><td><a href="./quick-links-index.html">Short Links</a></td><td>Create branded Web and App Links in the Branch Dashboard. Activation does <strong>not</strong> include Ad Links.</td></tr><tr><td><a href="./san-deferred-deep-linking.html">Deferred Deep Links</a></td><td>Configure deep linking to execute through an install. Includes <a href="./nativelink-deferred-deep-linking.html">NativeLink</a>.</td></tr><tr><td><a href="./qr-codes-builder.html">Custom QR Codes</a></td><td>Customize Branch QR Code logos, imagery, shapes, and colors to increase conversions right from the Branch Dashboard.</td></tr><tr><td><a href="./deep-linking-api.html">Deep Linking API</a></td><td>Generate web and app links at scale, and give them analytics tags.</td></tr><tr><td><a href="./linkhub.html#analytics">Link-Level Analytics</a></td><td>View your campaign performance through customizable tables with download capabilities.</td></tr><tr><td><a href="./data-integration-partners.html">Data Integration Partners</a> (webhooks)</td><td>Export install and down-funnel user action data to your internal systems for analysis, as it occurs. You can have <strong>up to 3</strong> webhooks configured with custom rate limits.</td></tr><tr><td><a href="./basic-link-configuration.html#use-your-own-domain">Custom Branded Domain</a></td><td>Configure your Branch Links to use your own custom domain.</td></tr><tr><td><a href="./add-and-manager-users.html">Additional Users</a></td><td>Add up to 5 additional users to your Branch account.</td></tr></tbody></table><h2 id="add-ons" tabindex="-1">Add-ons <a class="header-anchor" href="#add-ons" aria-label="Permalink to &quot;Add-ons&quot;">​</a></h2><p>The Branch Growth Platform has several add-ons that offer more sophisticated marketing solutions designed for specific use-cases.</p><h3 id="advanced-compliance" tabindex="-1">Advanced Compliance <a class="header-anchor" href="#advanced-compliance" aria-label="Permalink to &quot;Advanced Compliance&quot;">​</a></h3><p>Our Advanced Compliance add-on is a response to evolving healthcare regulations and what is considered PHI. This solution is most suited for customers in healthcare or similar highly regulated industries.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="./advanced-compliance.html">Advanced Privacy-Preserving Attribution</a></td><td>Supports safe and proper attribution when handling data related to protected health information (PHI).</td></tr><tr><td><a href="./advanced-compliance.html">Advanced Security Gateway</a></td><td>Helps secure data through an isolated network with strong authentication and encryption.</td></tr><tr><td><a href="./advanced-compliance.html">Protected API</a></td><td>All incoming data flows through a protected endpoint that identifies and obfuscates PHI.</td></tr></tbody></table><h3 id="advanced-data-feeds" tabindex="-1">Advanced Data Feeds <a class="header-anchor" href="#advanced-data-feeds" aria-label="Permalink to &quot;Advanced Data Feeds&quot;">​</a></h3><p>If you care about your attribution data (both inside and outside of Branch) and want a more holistic picture of your reporting as user actions take place, our Advanced Data Feeds add-on has you covered.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="./scheduled-log-exports-api.html">Scheduled Log Exports API</a></td><td>Schedule daily or hourly exports of log-level data from Branch.</td></tr><tr><td><a href="./cross-events-export-api.html">Cross-Events Export API</a></td><td>Query aggregate-level data, with no limits on dimensions or number of results returned.</td></tr><tr><td><a href="./unified-analytics-export.html">Unified Analytics Export</a></td><td>Funnel your SKAN and non-SKAN data into your preferred data warehouse.</td></tr><tr><td><a href="./data-integration-partners.html">Data Integration Partners</a> (webhooks)</td><td>Export install and down-funnel user action data to your internal systems for analysis, as it occurs.</td></tr><tr><td><a href="./exporting-data-analytics-providers.html">Outbound Data Integrations</a></td><td>Automatically send Branch data to your other analytics services and marketing tools.</td></tr></tbody></table><h3 id="eu-data-center" tabindex="-1">EU Data Center <a class="header-anchor" href="#eu-data-center" aria-label="Permalink to &quot;EU Data Center&quot;">​</a></h3><p>The EU Data Center add-on is for customers that want to reduce the amount of personal data processing and storage undertaken in the United States. With this add-on, certain processing and storage activities are kept in the E.U. on our AWS servers.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="https://www.branch.io/resources/blog/european-union-data-footprint-update/" target="_blank" rel="noreferrer">EU Endpoints</a></td><td>Communicate with Branch SDK and Journeys endpoints that are hosted in the EU.</td></tr><tr><td><a href="https://www.branch.io/resources/blog/european-union-data-footprint-update/" target="_blank" rel="noreferrer">Imports Stored in EU</a></td><td>Request that data received by Branch (including PII) be stored in the EU.</td></tr><tr><td><a href="./eu-hosted-data-for-new-enterprise-customers.html">Exports Occur in EU</a></td><td>Trigger exports and queries related to log-level data to occur in the EU.</td></tr></tbody></table><h2 id="services" tabindex="-1">Services <a class="header-anchor" href="#services" aria-label="Permalink to &quot;Services&quot;">​</a></h2><p>Branch is committed to offering the right support when you need it as your brand grows with our product.</p><table tabindex="0"><thead><tr><th>Service</th><th>Description</th></tr></thead><tbody><tr><td><a href="./support-best-practices.html#account-management">Account Management</a></td><td>Work with our dedicated team for personalized support and product recommendations.</td></tr><tr><td><a href="./professional-services.html">Professional Services</a></td><td>Lean on our industry experts for complex use cases, integrations, and platform configurations.</td></tr><tr><td><a href="./support-best-practices.html#premium-support">Premium Support</a></td><td>Rely on our Premium Support Services to resolve your concerns quickly.</td></tr></tbody></table><h2 id="volume-credits" tabindex="-1">Volume credits <a class="header-anchor" href="#volume-credits" aria-label="Permalink to &quot;Volume credits&quot;">​</a></h2><p>Branch uses the concept of <strong>volume credits</strong> for billing.</p><p>Volume credits correspond to the number of end-user actions tracked, attributed, and reported on in Branch.</p><p>You will need to add a certain number of volume credits to your Branch account when purchasing either Engagement or Performance. You can also add additional monthly volume credits for a fee. Overages get billed at a &quot;per volume credit&quot; rate.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><p>Use the resources below for more information about pricing and packaging.</p><h4 id="website" tabindex="-1">Website <a class="header-anchor" href="#website" aria-label="Permalink to &quot;Website&quot;">​</a></h4><p>Learn more about our pricing model on the <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Branch website</a>.</p><h4 id="sales" tabindex="-1">Sales <a class="header-anchor" href="#sales" aria-label="Permalink to &quot;Sales&quot;">​</a></h4><p>When you&#39;re ready to discuss Branch packaging, <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our sales team</a> to get started.</p>',58)])])}const m=e(o,[["render",i]]);export{p as __pageData,m as default};
